# Convert to stim.PauliString
stabs = [stim.PauliString(s) for s in stabilizers_raw]
print(f"Number of stabilizers: {len(stabs)}")
print(f"Number of qubits: 135")

# Create tableau from stabilizers
try:
    tab = stim.Tableau.from_stabilizers(stabs, allow_underconstrained=True, allow_redundant=True)
    print("Tableau created successfully!")
    print(f"Tableau size: {len(tab)}")
except Exception as e:
    print(f"Error creating tableau: {e}")
